-- Migration 005: Import New RRP PDF effective 18 May 2026
-- Source: New RRP - 2026 (18 May 2026).pdf

BEGIN;

ALTER TABLE public.rrp_entries
  ADD COLUMN IF NOT EXISTS source_file TEXT,
  ADD COLUMN IF NOT EXISTS source_page INTEGER,
  ADD COLUMN IF NOT EXISTS source_section TEXT;

CREATE TABLE IF NOT EXISTS public.rrp_source_pages (
  source_file TEXT NOT NULL,
  page_number INTEGER NOT NULL,
  page_text TEXT NOT NULL,
  extracted_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (source_file, page_number)
);

ALTER TABLE public.rrp_source_pages ENABLE ROW LEVEL SECURITY;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.rrp_source_pages TO authenticated;
DROP POLICY IF EXISTS rrp_source_pages_read ON public.rrp_source_pages;
CREATE POLICY rrp_source_pages_read ON public.rrp_source_pages FOR SELECT TO authenticated USING (true);
DROP POLICY IF EXISTS rrp_source_pages_admin_write ON public.rrp_source_pages;
CREATE POLICY rrp_source_pages_admin_write ON public.rrp_source_pages FOR ALL TO authenticated USING (public.current_app_role() = 'admin') WITH CHECK (public.current_app_role() = 'admin');

CREATE OR REPLACE FUNCTION public.import_rrp_entry_seed(
  p_blind_type TEXT,
  p_fabric_group TEXT,
  p_fabric_name TEXT,
  p_width_max TEXT,
  p_uom TEXT,
  p_price_map JSONB,
  p_sort_order INTEGER,
  p_source_file TEXT,
  p_source_page INTEGER,
  p_source_section TEXT
)
RETURNS VOID
LANGUAGE plpgsql
AS $$
DECLARE
  v_wo NUMERIC := NULLIF(p_price_map ->> 'Roller Blinds Without Headrail', '')::numeric;
  v_head NUMERIC := NULLIF(p_price_map ->> 'Roller Blinds With Headrail', '')::numeric;
  v_dec NUMERIC := NULLIF(p_price_map ->> 'Roller Blinds With Decorative Cassette', '')::numeric;
  v_square NUMERIC := NULLIF(p_price_map ->> 'Roller Blinds With Decorative Square Cassette', '')::numeric;
BEGIN
  INSERT INTO public.rrp_entries(
    blind_type, fabric_group, fabric_name, width_max, uom,
    rrp_wo_headrail, rrp_w_headrail, rrp_w_plain_cassette, rrp_w_dec_cassette,
    sort_order, price_map, source_file, source_page, source_section
  )
  VALUES (
    trim(p_blind_type), coalesce(nullif(trim(p_fabric_group), ''), 'General'), trim(p_fabric_name), nullif(trim(coalesce(p_width_max, '')), ''), coalesce(nullif(trim(p_uom), ''), 'SQM'),
    v_wo, v_head, v_dec, v_square,
    p_sort_order, coalesce(p_price_map, '{}'::jsonb), p_source_file, p_source_page, p_source_section
  )
  ON CONFLICT (blind_type, fabric_group, fabric_name)
  DO UPDATE SET
    width_max = EXCLUDED.width_max,
    uom = EXCLUDED.uom,
    rrp_wo_headrail = EXCLUDED.rrp_wo_headrail,
    rrp_w_headrail = EXCLUDED.rrp_w_headrail,
    rrp_w_plain_cassette = EXCLUDED.rrp_w_plain_cassette,
    rrp_w_dec_cassette = EXCLUDED.rrp_w_dec_cassette,
    sort_order = EXCLUDED.sort_order,
    price_map = EXCLUDED.price_map,
    source_file = EXCLUDED.source_file,
    source_page = EXCLUDED.source_page,
    source_section = EXCLUDED.source_section,
    updated_at = NOW();
END;
$$;

