      ('Roman Blind', 'Roman Blinds Stitchless Mechanism', 'VIOLET, SKYLER, ORIBI, ELENA, BAMBERG'),
      ('Aluminium Venetian Blind', 'Aluminium Venetian Series', '25 MM CLASSIC'),
      ('Wooden Venetian Blind', 'Wooden Venetian Series', 'TECH WOOD 50MM'),
      ('Cellular Blind', 'Classic Blinds', 'TRANSLUCENT - Canyon'),
      ('Cellular Blind', 'Classic Blinds', 'BLACK OUT - Cliff'),
      ('Cellular Blind', 'Classic Blinds', 'SHEER FABRIC - Vega'),
      ('Cellular Blind', 'Top Down Bottom Up', 'TRANSLUCENT - Canyon'),
      ('Cellular Blind', 'Top Down Bottom Up', 'BLACK OUT - Cliff'),
      ('Cellular Blind', 'Top Down Bottom Up', 'SHEER FABRIC - Vega'),
      ('Cellular Blind', 'Day Night', 'TRANSLUCENT + SHEER - Vega+Canyon'),
      ('Cellular Blind', 'Day Night', 'BLACK OUT + SHEER - Cliff+Vega')
    ) AS seed(root_name, group_name, leaf_name)
  LOOP
    v_root := public.ensure_master_node_seed(NULL, rec.root_name, FALSE, 0);
    UPDATE public.master_nodes SET page_id = v_blinds_page WHERE id = v_root AND page_id IS DISTINCT FROM v_blinds_page;
    v_group := public.ensure_master_node_seed(v_root, rec.group_name, FALSE, 0);
    PERFORM public.ensure_master_node_seed(v_group, rec.leaf_name, FALSE, 0);
  END LOOP;
END;
$$;

DO $$
DECLARE
  v_group UUID;
BEGIN
  v_group := public.ensure_mechanism_group_seed('Roller Blind Mechanisms', 'RRP mechanism/options imported from New RRP - 2026 (18 May 2026).pdf', 10);
  PERFORM public.ensure_mechanism_option_seed(v_group, 'Without Headrail', 'Roller Blinds Without Headrail', 'Roller Blinds Without Headrail', 10);
  PERFORM public.ensure_mechanism_option_seed(v_group, 'With Headrail', 'Roller Blinds With Headrail', 'Roller Blinds With Headrail', 20);
  PERFORM public.ensure_mechanism_option_seed(v_group, 'With Decorative Cassette', 'Roller Blinds With Decorative Cassette', 'Roller Blinds With Decorative Cassette', 30);
  PERFORM public.ensure_mechanism_option_seed(v_group, 'With Decorative Square Cassette', 'Roller Blinds With Decorative Square Cassette', 'Roller Blinds With Decorative Square Cassette', 40);
  INSERT INTO public.master_mechanism_groups(master_node_id, mechanism_group_id, sort_order)
  SELECT mn.id, v_group, 10 FROM public.master_nodes mn
  WHERE mn.parent_id IS NULL AND mn.normalized_name = public.normalize_master_seed_name('Roller Blind')
  ON CONFLICT (master_node_id, mechanism_group_id) DO NOTHING;
  v_group := public.ensure_mechanism_group_seed('Sheer Dimout Blind Mechanisms', 'RRP mechanism/options imported from New RRP - 2026 (18 May 2026).pdf', 20);
