  PERFORM public.ensure_mechanism_option_seed(v_group, 'Premium Mechanism with Plain Cassette', 'Sheer Dimout Blinds Premium Mechanism with Plain Cassette', 'Sheer Dimout Blinds Premium Mechanism with Plain Cassette', 30);
  PERFORM public.ensure_mechanism_option_seed(v_group, 'Premium Mechanism with Decorative Cassette', 'Sheer Dimout Blinds Premium Mechanism with Decorative Cassette', 'Sheer Dimout Blinds Premium Mechanism with Decorative Cassette', 40);
  PERFORM public.ensure_mechanism_option_seed(v_group, 'Premium Mechanism with Decorative Square Cassette', 'Sheer Dimout Blinds Premium Mechanism with Decorative Square Cassette', 'Sheer Dimout Blinds Premium Mechanism with Decorative Square Cassette', 50);
  INSERT INTO public.master_mechanism_groups(master_node_id, mechanism_group_id, sort_order)
  SELECT mn.id, v_group, 20 FROM public.master_nodes mn
  WHERE mn.parent_id IS NULL AND mn.normalized_name = public.normalize_master_seed_name('Sheer Dimout Blind')
  ON CONFLICT (master_node_id, mechanism_group_id) DO NOTHING;
  v_group := public.ensure_mechanism_group_seed('S-Contour Blind Mechanisms', 'RRP mechanism/options imported from New RRP - 2026 (18 May 2026).pdf', 30);
  PERFORM public.ensure_mechanism_option_seed(v_group, 'With Decorative Cassette', 'S-Contour Blinds With Decorative Cassette', 'S-Contour Blinds With Decorative Cassette', 10);
  PERFORM public.ensure_mechanism_option_seed(v_group, 'With Decorative Square Cassette', 'S-Contour Blinds With Decorative Square Cassette', 'S-Contour Blinds With Decorative Square Cassette', 20);
  INSERT INTO public.master_mechanism_groups(master_node_id, mechanism_group_id, sort_order)
  SELECT mn.id, v_group, 30 FROM public.master_nodes mn
  WHERE mn.parent_id IS NULL AND mn.normalized_name = public.normalize_master_seed_name('S-Contour Blind')
  ON CONFLICT (master_node_id, mechanism_group_id) DO NOTHING;
  v_group := public.ensure_mechanism_group_seed('Vertical Blind Mechanisms', 'RRP mechanism/options imported from New RRP - 2026 (18 May 2026).pdf', 40);
  PERFORM public.ensure_mechanism_option_seed(v_group, '100MM', 'Vertical Blinds 100MM', 'Vertical Blinds 100MM', 10);
  INSERT INTO public.master_mechanism_groups(master_node_id, mechanism_group_id, sort_order)
  SELECT mn.id, v_group, 40 FROM public.master_nodes mn
  WHERE mn.parent_id IS NULL AND mn.normalized_name = public.normalize_master_seed_name('Vertical Blind')
  ON CONFLICT (master_node_id, mechanism_group_id) DO NOTHING;
  v_group := public.ensure_mechanism_group_seed('Roman Blind Mechanisms', 'RRP mechanism/options imported from New RRP - 2026 (18 May 2026).pdf', 50);
  PERFORM public.ensure_mechanism_option_seed(v_group, 'With Chain Mechanism', 'Roman Blinds With Chain Mechanism', 'Roman Blinds With Chain Mechanism', 10);
  PERFORM public.ensure_mechanism_option_seed(v_group, 'With Decorative Cassette', 'Roman Blinds With Decorative Cassette', 'Roman Blinds With Decorative Cassette', 20);
  PERFORM public.ensure_mechanism_option_seed(v_group, 'With Decorative Square Cassette', 'Roman Blinds With Decorative Square Cassette', 'Roman Blinds With Decorative Square Cassette', 30);
  INSERT INTO public.master_mechanism_groups(master_node_id, mechanism_group_id, sort_order)
  SELECT mn.id, v_group, 50 FROM public.master_nodes mn
  WHERE mn.parent_id IS NULL AND mn.normalized_name = public.normalize_master_seed_name('Roman Blind')
  ON CONFLICT (master_node_id, mechanism_group_id) DO NOTHING;
  v_group := public.ensure_mechanism_group_seed('Wooden Venetian Blind Mechanisms', 'RRP mechanism/options imported from New RRP - 2026 (18 May 2026).pdf', 60);
  PERFORM public.ensure_mechanism_option_seed(v_group, 'Ladder Tape with Mono Mechanism', 'Wooden Venetian Blinds Ladder Tape with Mono Mechanism', 'Wooden Venetian Blinds Ladder Tape with Mono Mechanism', 10);
  PERFORM public.ensure_mechanism_option_seed(v_group, 'Ladder String with Mono Mechanism', 'Wooden Venetian Blinds Ladder String with Mono Mechanism', 'Wooden Venetian Blinds Ladder String with Mono Mechanism', 20);
  INSERT INTO public.master_mechanism_groups(master_node_id, mechanism_group_id, sort_order)
  SELECT mn.id, v_group, 60 FROM public.master_nodes mn
  WHERE mn.parent_id IS NULL AND mn.normalized_name = public.normalize_master_seed_name('Wooden Venetian Blind')
  ON CONFLICT (master_node_id, mechanism_group_id) DO NOTHING;
  v_group := public.ensure_mechanism_group_seed('Aluminium Venetian Blind Mechanisms', 'RRP mechanism/options imported from New RRP - 2026 (18 May 2026).pdf', 70);
  PERFORM public.ensure_mechanism_option_seed(v_group, 'Ladder String', 'Aluminium Venetian Blinds Ladder String', 'Aluminium Venetian Blinds Ladder String', 10);
  INSERT INTO public.master_mechanism_groups(master_node_id, mechanism_group_id, sort_order)
  SELECT mn.id, v_group, 70 FROM public.master_nodes mn
  WHERE mn.parent_id IS NULL AND mn.normalized_name = public.normalize_master_seed_name('Aluminium Venetian Blind')
  ON CONFLICT (master_node_id, mechanism_group_id) DO NOTHING;
  v_group := public.ensure_mechanism_group_seed('Cellular Blind Mechanisms', 'RRP mechanism/options imported from New RRP - 2026 (18 May 2026).pdf', 80);
  PERFORM public.ensure_mechanism_option_seed(v_group, 'Mono Mech', 'Cellular Blinds Mono Mech', 'Cellular Blinds Mono Mech', 10);
  INSERT INTO public.master_mechanism_groups(master_node_id, mechanism_group_id, sort_order)
  SELECT mn.id, v_group, 80 FROM public.master_nodes mn
  WHERE mn.parent_id IS NULL AND mn.normalized_name = public.normalize_master_seed_name('Cellular Blind')
  ON CONFLICT (master_node_id, mechanism_group_id) DO NOTHING;
